import React from 'react';
import { Card, Stack, Text, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Card padding={24} shadow="md" radius="xl" border={true}>
      <Stack gap={24} aria-label={`Weather in ${city}, ${condition} at ${temperature}°${unit}`}>
        {/* Header Section */}
        <Stack gap={4} align="center">
          <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">
            {city}
          </Text>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
            {condition}
          </Text>
        </Stack>

        {/* Current Temp */}
        <Stack align="center">
          <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)">
            {temperature}°{unit}
          </Text>
        </Stack>

        {/* Current Metrics */}
        <Stack direction="horizontal" justify="center" gap={32}>
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Humidity
            </Text>
            <Text weight="medium">{humidity}%</Text>
          </Stack>
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Wind
            </Text>
            <Text weight="medium">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider color="var(--ggui-color-outlineVariant)" margin={0} />

        {/* 5-Day Forecast Strip */}
        <Stack direction="horizontal" justify="between" gap={8}>
          {forecast.map((item, index) => (
            <Stack 
              key={index} 
              align="center" 
              gap={8}
            >
              <Text variant="caption" weight="medium">
                {item.day ?? '---'}
              </Text>
              <Text size="xl" aria-hidden="true">
                {item.icon ?? '☁️'}
              </Text>
              <Text size="sm" weight="medium">
                {item.high ?? 0}°/{item.low ?? 0}°
              </Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Divider,
  Box,
  Spacer,
} from '@ggui-ai/design/primitives';
import {
  FormField,
  Input,
  TextArea,
  Checkbox,
  RadioGroup,
  Button,
  Progress,
} from '@ggui-ai/design/components';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit: (data: Record<string, any>) => void;
}

export default function GeneratedComponent(props: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: '',
    features: [] as string[],
    comments: '',
  });
  const [errors, setErrors] = useState({ name: '', email: '' });

  useEffect(() => {
    const handler = (e: any) => console.log('Agent data:', e.detail);
    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, []);

  const validateStep1 = () => {
    const newErrors = {
      name: !formData.name.trim() ? 'Name is required' : '',
      email: !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)
        ? 'Valid email is required'
        : '',
    };
    setErrors(newErrors);
    return !newErrors.name && !newErrors.email;
  };

  const handleNext = () => {
    if (currentStep === 1 && !validateStep1()) return;
    setCurrentStep((prev) => Math.min(prev + 1, 5));
  };

  const handleBack = () => setCurrentStep((prev) => Math.max(prev - 1, 1));

  const handleSubmit = async () => {
    setIsSubmitting(true);
    await new Promise((resolve) => setTimeout(resolve, 1000));
    props.onSubmit(formData);
    setIsSubmitting(false);
  };

  const stepLabels = ['Personal Info', 'Satisfaction', 'Features', 'Comments', 'Review'];

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack gap="var(--ggui-spacing-2, 8px)">
          <Heading level={2}>Customer Survey</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {currentStep} of 5: {stepLabels[currentStep - 1]}
          </Text>
          <Progress value={(currentStep / 5) * 100} max={100} size="md" />
        </Stack>

        <Card padding="var(--ggui-spacing-6, 24px)" shadow="md">
          {currentStep === 1 && (
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3}>Personal Information</Heading>
              <FormField label="Name" required error={errors.name}>
                <Input value={formData.name} onChange={(v) => setFormData({ ...formData, name: v })} placeholder="John Doe" />
              </FormField>
              <FormField label="Email" required error={errors.email}>
                <Input type="email" value={formData.email} onChange={(v) => setFormData({ ...formData, email: v })} placeholder="john@example.com" />
              </FormField>
            </Stack>
          )}

          {currentStep === 2 && (
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3}>Satisfaction Rating</Heading>
              <RadioGroup 
                label="How satisfied are you?" 
                value={formData.satisfaction} 
                onChange={(v) => setFormData({ ...formData, satisfaction: v })}
                options={props.satisfactionLabels.map((l, i) => ({ value: (i + 1).toString(), label: l }))}
              />
            </Stack>
          )}

          {currentStep === 3 && (
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3}>Feature Interests</Heading>
              {props.featureOptions.map((feat) => (
                <Checkbox 
                  key={feat} 
                  label={feat} 
                  checked={formData.features.includes(feat)} 
                  onChange={(c) => setFormData(p => ({...p, features: c ? [...p.features, feat] : p.features.filter(f => f !== feat)}))} 
                />
              ))}
            </Stack>
          )}

          {currentStep === 4 && (
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3}>Additional Comments</Heading>
              <TextArea label="Comments" value={formData.comments} onChange={(v) => setFormData({...formData, comments: v})} rows={4} maxLength={500} showCount />
            </Stack>
          )}

          {currentStep === 5 && (
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3}>Review Your Answers</Heading>
              <Text><strong>Name:</strong> {formData.name}</Text>
              <Text><strong>Email:</strong> {formData.email}</Text>
              <Text><strong>Satisfaction:</strong> {props.satisfactionLabels[parseInt(formData.satisfaction) - 1]}</Text>
              <Text><strong>Features:</strong> {formData.features.join(', ') || 'None selected'}</Text>
              <Text><strong>Comments:</strong> {formData.comments || 'No comments provided'}</Text>
            </Stack>
          )}
        </Card>

        <Divider margin="var(--ggui-spacing-4, 16px)" />

        <Stack direction="horizontal" justify="between">
          <Button variant="secondary" onClick={handleBack} disabled={currentStep === 1}>Back</Button>
          {currentStep < 5 ? (
            <Button onClick={handleNext}>Next</Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit} loading={isSubmitting}>Submit Survey</Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Box,
  Card,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Badge,
  Avatar,
  Divider,
  Spacer,
} from '@ggui-ai/design/primitives';

interface Props {
  tasks: Array<{
    id?: string;
    title?: string;
    priority?: 'low' | 'medium' | 'high';
    assignee?: string;
    column?: string;
    dueDate?: string;
  }>;
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate?: (payload: { action: 'move' | 'edit' | 'create'; taskId: string; data: any }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [tasks, setTasks] = useState(props.tasks || []);
  const [isAdding, setIsAdding] = useState<string | null>(null);
  const [newTask, setNewTask] = useState({ title: '', priority: 'medium' as 'low' | 'medium' | 'high' });
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    const handleAgentData = (e: any) => {
      const detail = e.detail || {};
      if (detail.action && detail.taskId) {
        handleTaskUpdate(detail.action, detail.taskId, detail.data);
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
  }, []);

  const handleTaskUpdate = (action: 'move' | 'edit' | 'create', taskId: string, data: any) => {
    setIsSubmitting(true);
    if (action === 'create') {
      const createdTask = { id: Date.now().toString(), ...data };
      setTasks((prev) => [...prev, createdTask]);
      setIsAdding(null);
      setNewTask({ title: '', priority: 'medium' });
    } else {
      setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, ...data } : t)));
    }
    props.onTaskUpdate?.({ action, taskId, data });
    setIsSubmitting(false);
  };

  const getPriorityVariant = (p?: string) => {
    switch (p) {
      case 'high': return 'error';
      case 'medium': return 'warning';
      default: return 'success';
    }
  };

  const completedCount = tasks.filter((t) => t.column === 'done').length;

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Card padding="var(--ggui-spacing-4, 16px)" border={true} radius="lg">
          <Stack gap="var(--ggui-spacing-2, 8px)">
            <Heading level={2}>Project Board</Heading>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Total Tasks: {tasks.length} | Completed: {completedCount}
            </Text>
          </Stack>
        </Card>

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" align="start" wrap={true}>
          {props.columns.map((col) => (
            <Box
              key={col.id}
              padding="var(--ggui-spacing-4, 16px)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-lg, 12px)"
              style={{ width: 320 }}
            >
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Stack direction="horizontal" justify="between" align="center">
                  <Heading level={4}>{col.name}</Heading>
                  <Badge variant="secondary" pill={true}>
                    {tasks.filter((t) => t.column === col.id).length}
                  </Badge>
                </Stack>

                <Stack gap="var(--ggui-spacing-3, 12px)">
                  {tasks
                    .filter((t) => t.column === col.id)
                    .map((task) => (
                      <Card key={task.id} padding="var(--ggui-spacing-3, 12px)" shadow="sm" border={true} radius="md">
                        <Stack gap="var(--ggui-spacing-2, 8px)">
                          <Text weight="semibold">{task.title}</Text>
                          <Stack direction="horizontal" justify="between" align="center">
                            <Badge variant={getPriorityVariant(task.priority) as any} pill={true}>
                              {task.priority}
                            </Badge>
                            <Avatar name={task.assignee ?? 'T'} size={24} shape="circle" />
                          </Stack>
                          {task.dueDate && <Text variant="caption">Due: {task.dueDate}</Text>}
                          <Divider margin={8} />
                          <Select
                            label="Move to"
                            value={col.id!}
                            onChange={(newCol) => handleTaskUpdate('move', task.id!, { column: newCol })}
                            options={props.columns.map((c) => ({ value: c.id!, label: c.name! }))}
                          />
                        </Stack>
                      </Card>
                    ))}
                </Stack>

                {isAdding === col.id ? (
                  <Card padding="var(--ggui-spacing-3, 12px)" border={true} radius="md">
                    <Stack gap="var(--ggui-spacing-3, 12px)">
                      <Input label="Task Title" value={newTask.title} onChange={(val) => setNewTask({ ...newTask, title: val })} />
                      <Select
                        label="Priority"
                        value={newTask.priority}
                        onChange={(val) => setNewTask({ ...newTask, priority: val as any })}
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                      />
                      <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)">
                        <Button
                          loading={isSubmitting}
                          onClick={() => {
                            if (newTask.title.trim()) {
                              handleTaskUpdate('create', 'new', { ...newTask, column: col.id });
                            }
                          }}
                        >
                          Save
                        </Button>
                        <Button variant="ghost" onClick={() => setIsAdding(null)}>
                          Cancel
                        </Button>
                      </Stack>
                    </Stack>
                  </Card>
                ) : (
                  <Button variant="outline" onClick={() => setIsAdding(col.id!)}>
                    + Add Task
                  </Button>
                )}
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Box, Stack, Card, Text, Heading, Input } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const getCategoryColor = (category?: string) => {
  switch (category) {
    case 'noble-gas':
      return 'var(--ggui-color-info-500, #06b6d4)';
    case 'nonmetal':
      return 'var(--ggui-color-success-500, #22c55e)';
    case 'alkali-metal':
      return 'var(--ggui-color-warning-500, #f59e0b)';
    case 'transition-metal':
      return 'var(--ggui-color-primary-500, #0ea5e9)';
    default:
      return 'var(--ggui-color-outlineVariant, #e4e4e7)';
  }
};

export default function GeneratedComponent(props: Props) {
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);
  const [query, setQuery] = useState("");

  const filtered = useMemo(() => {
    const q = query.toLowerCase();
    return props.elements.filter((e) =>
      e.name?.toLowerCase().includes(q) || e.symbol?.toLowerCase().includes(q)
    );
  }, [props.elements, query]);

  const categories = Array.from(new Set(props.elements.map((e) => e.category || 'unknown')));

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Heading level={1}>Periodic Table</Heading>

        <Input
          label="Search elements by name or symbol"
          value={query}
          onChange={(val) => setQuery(val)}
          placeholder="e.g. Hydrogen or H"
        />

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1, 4px)',
            width: '100%',
          }}
        >
          {props.elements.map((el, i) => {
            const isVisible = filtered.some((f) => f.atomicNumber === el.atomicNumber);
            return (
              <button
                key={el.atomicNumber ?? i}
                onClick={() => setSelected(el)}
                aria-label={`Element: ${el.name}, Symbol: ${el.symbol}`}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  background: getCategoryColor(el.category),
                  padding: 'var(--ggui-spacing-2, 8px)',
                  cursor: 'pointer',
                  opacity: isVisible ? 1 : 0.2,
                  transition: 'transform 200ms ease, opacity 200ms ease',
                  textAlign: 'left',
                  height: '60px',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'space-between',
                  outline: 'none',
                }}
                onMouseOver={(e) => { e.currentTarget.style.transform = 'scale(1.05)'; }}
                onMouseOut={(e) => { e.currentTarget.style.transform = 'scale(1)'; }}
              >
                <Text size="xs" color="var(--ggui-color-onSurface, #18181b)">{el.atomicNumber}</Text>
                <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">{el.symbol}</Heading>
              </button>
            );
          })}
        </Box>

        {selected && (
          <Card padding="var(--ggui-spacing-6, 24px)">
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Heading level={3}>{selected.name}</Heading>
              <Text>Symbol: {selected.symbol}</Text>
              <Text>Atomic Number: {selected.atomicNumber}</Text>
              <Text>Atomic Weight: {selected.atomicWeight}</Text>
              <Text>Category: {selected.category}</Text>
            </Stack>
          </Card>
        )}

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
          {categories.map((cat) => (
            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center" key={cat}>
              <Box borderRadius="var(--ggui-shape-radius-sm, 4px)" style={{ width: 16, height: 16, background: getCategoryColor(cat) }} />
              <Text variant="caption">{cat}</Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { Card, Stack, Box, Text, Heading, Input, Button, Badge, Spacer, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback for sending messages */
  onSendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [inputValue, setInputValue] = useState('');
  const [messages, setMessages] = useState(props.messages);
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setMessages(props.messages);
  }, [props.messages]);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      const data = event.detail ?? {};
      if (data.text) {
        setMessages((prev) => [
          ...prev,
          {
            sender: data.sender,
            text: data.text,
            timestamp: data.timestamp ?? new Date().toISOString(),
          },
        ]);
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  useEffect(() => {
    if (scrollContainerRef.current) {
      scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = () => {
    if (inputValue.trim()) {
      props.onSendMessage({
        text: inputValue.trim(),
        timestamp: new Date().toISOString(),
      });
      setInputValue('');
    }
  };

  return (
    <Card shadow="md" padding={0} border={true} radius="lg">
      <Box padding={16} style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
        <Stack direction="horizontal" justify="between" align="center" gap={16}>
          <Heading level={4}>{props.title}</Heading>
          {props.participantCount !== undefined && (
            <Badge variant="secondary">{props.participantCount} participants</Badge>
          )}
        </Stack>
      </Box>

      <div
        ref={scrollContainerRef}
        style={{ height: '400px', overflowY: 'auto', padding: 'var(--ggui-spacing-4, 16px)' }}
        role="log"
        aria-live="polite"
      >
        <Stack gap={12}>
          {messages.map((msg, index) => {
            const isOwn = msg.sender === props.currentUser;
            const time = msg.timestamp
              ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
              : '';

            const showName = index === 0 || messages[index - 1]?.sender !== msg.sender;

            return (
              <Stack key={index} align={isOwn ? 'end' : 'start'} gap={4}>
                {showName && (
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {msg.sender ?? 'Unknown'}
                  </Text>
                )}
                <Box
                  padding={12}
                  borderRadius={12}
                  background={isOwn ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                >
                  <Text color={isOwn ? 'var(--ggui-color-surface, #ffffff)' : 'var(--ggui-color-onSurface, #18181b)'}>
                    {msg.text}
                  </Text>
                </Box>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {time}
                </Text>
              </Stack>
            );
          })}
        </Stack>
      </div>

      <Box padding={16} style={{ borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
        <Stack direction="horizontal" gap={8} align="end">
          <div style={{ flex: 1 }}>
            <Input
              label="Message"
              value={inputValue}
              onChange={(val) => setInputValue(val)}
              placeholder="Type a message..."
              onKeyDown={(e: React.KeyboardEvent) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  handleSend();
                }
              }}
            />
          </div>
          <Button
            variant="primary"
            onClick={handleSend}
            disabled={!inputValue.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

