import React, { useState, useEffect } from 'react';
import {
  Card,
  Container,
  Stack,
  Text,
  Heading,
  Badge,
  Icon,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{
    symbol?: string;
    name?: string;
    price?: number;
    change?: number;
    changePercent?: number;
  }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [stocks, setStocks] = useState(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState(props.lastUpdated ?? new Date().toISOString());
  const [status, setStatus] = useState<'Live' | 'Connecting'>('Connecting');

  useEffect(() => {
    const handleAgentData = (event: any) => {
      const data = event.detail;
      if (Array.isArray(data)) {
        setStocks(data);
        setLastUpdated(new Date().toISOString());
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData);

    const timer = setTimeout(() => setStatus('Live'), 1500);

    return () => {
      window.removeEventListener('ggui:agent-data', handleAgentData);
      clearTimeout(timer);
    };
  }, []);

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6, 24px)">
      <main role="main">
        <Stack gap="var(--ggui-spacing-6, 24px)">
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={1}>Market Watch</Heading>
            <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" align="center">
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                aria-live="polite"
              >
                Last Updated: {new Date(lastUpdated).toLocaleTimeString()}
              </Text>
              <Badge variant={status === 'Live' ? 'success' : 'warning'}>
                {status}
              </Badge>
            </Stack>
          </Stack>

          <div
            role="list"
            style={{
              display: 'grid',
              gridTemplateColumns: '1fr',
              gap: 'var(--ggui-spacing-6, 24px)',
            }}
          >
            <style>{`
              @media (min-width: 768px) {
                div[role="list"] { grid-template-columns: repeat(3, 1fr) !important; }
              }
            `}</style>

            {stocks.map((stock, index) => {
              const price = stock.price ?? 0;
              const change = stock.change ?? 0;
              const changePercent = stock.changePercent ?? 0;
              const isPositive = change >= 0;
              const semanticColor = isPositive
                ? 'var(--ggui-color-success, #16a34a)'
                : 'var(--ggui-color-error, #dc2626)';

              return (
                <div key={stock.symbol ?? index} role="listitem">
                  <Card padding="20px" shadow="sm" border={true} radius="lg">
                    <Stack gap="var(--ggui-spacing-2, 8px)">
                      <Heading level={3}>{stock.symbol ?? 'N/A'}</Heading>
                      <Text
                        variant="bodySmall"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      >
                        {stock.name ?? 'Unknown'}
                      </Text>
                      <Text weight="bold" size="2xl">
                        ${price.toFixed(2)}
                      </Text>
                      <Stack direction="horizontal" gap="var(--ggui-spacing-1, 4px)" align="center">
                        <Icon
                          name={isPositive ? 'chevron-up' : 'chevron-down'}
                          size={12}
                          color={semanticColor}
                        />
                        <Text variant="label" color={semanticColor}>
                          {Math.abs(change).toFixed(2)} ({Math.abs(changePercent).toFixed(2)}%)
                        </Text>
                      </Stack>
                    </Stack>
                  </Card>
                </div>
              );
            })}
          </div>
        </Stack>
      </main>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Divider,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  RadioGroup,
  Progress,
} from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name ?? '',
    email: props.initialProfile?.email ?? '',
    avatar: props.initialProfile?.avatar ?? (props.avatarOptions[0] ?? ''),
    role: props.initialProfile?.role ?? (props.roleOptions[0] ?? ''),
    emailNotifications: props.initialProfile?.emailNotifications ?? true,
    theme: props.initialProfile?.theme ?? 'light',
  });

  useEffect(() => {
    const handleAgentData = (event: any) => {
      console.log('Agent Data Received:', event.detail);
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isEmailValid = emailRegex.test(formData.email);
  const isStep1Valid = formData.name.trim() !== '' && isEmailValid;

  const updateField = (key: string, value: any) => {
    setFormData((prev) => ({ ...prev, [key]: value }));
  };

  const nextStep = () => setCurrentStep((s) => Math.min(s + 1, 3));
  const prevStep = () => setCurrentStep((s) => Math.max(s - 1, 1));

  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-6, 24px)">
      <Card shadow="md" padding="var(--ggui-spacing-8, 32px)" radius="lg">
        <Stack gap="var(--ggui-spacing-6, 24px)">
          <Stack gap="var(--ggui-spacing-2, 8px)">
            <Heading level={3}>Onboarding - Step {currentStep} of 3</Heading>
            <Progress value={(currentStep / 3) * 100} variant="default" size="sm" />
          </Stack>

          <Box paddingY="var(--ggui-spacing-4, 16px)">
            {currentStep === 1 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Input
                  label="Full Name"
                  value={formData.name}
                  onChange={(v) => updateField('name', v)}
                  required
                />
                <Input
                  label="Email Address"
                  type="email"
                  value={formData.email}
                  onChange={(v) => updateField('email', v)}
                  error={formData.email && !isEmailValid ? "Invalid email format" : undefined}
                  required
                />
                <RadioGroup
                  label="Choose your Avatar"
                  value={formData.avatar}
                  onChange={(v) => updateField('avatar', v)}
                  options={props.avatarOptions.map((opt) => ({ value: opt, label: opt }))}
                  direction="horizontal"
                />
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Select
                  label="Role"
                  value={formData.role}
                  onChange={(v) => updateField('role', v)}
                  options={props.roleOptions.map((opt) => ({ value: opt, label: opt }))}
                />
                <Toggle
                  label="Enable Email Notifications"
                  checked={formData.emailNotifications}
                  onChange={(v) => updateField('emailNotifications', v)}
                />
                <Toggle
                  label="Dark Theme"
                  checked={formData.theme === 'dark'}
                  onChange={(v) => updateField('theme', v ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap="var(--ggui-spacing-3, 12px)">
                <Heading level={5}>Review your details</Heading>
                <Divider />
                {Object.entries(formData).map(([k, v]) => (
                  <Stack key={k} direction="horizontal" gap="var(--ggui-spacing-2, 8px)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {k.charAt(0).toUpperCase() + k.slice(1)}:
                    </Text>
                    <Text>{String(v)}</Text>
                  </Stack>
                ))}
              </Stack>
            )}
          </Box>

          <Divider />

          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" onClick={prevStep} disabled={currentStep === 1}>
              Go Back
            </Button>
            {currentStep < 3 ? (
              <Button
                variant="primary"
                onClick={nextStep}
                disabled={currentStep === 1 ? !isStep1Valid : false}
              >
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={() => props.onComplete?.(formData)}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
